using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    #region CalculateTotal - DataRow tests

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.1, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.2, 91.80, DisplayName = "Multiple items, 20% tax")]
    [DataRow(0.00, 10, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.1, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        // Arrange (DataRow doesn't support decimal literals, so cast from double)
        var price = (decimal)unitPrice;
        var tax = (decimal)taxRate;
        var expectedTotal = (decimal)expected;

        // Act
        var result = _calculator.CalculateTotal(price, quantity, tax);

        // Assert
        Assert.AreEqual(expectedTotal, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.1, "unitPrice", DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.1, "quantity", DisplayName = "Negative quantity")]
    public void CalculateTotal_WithNegativeValues_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    #endregion

    #region ApplyDiscount - DynamicData tests with ValueTuples

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        // Act
        var result = _calculator.ApplyDiscount(price, discountPercent);

        // Assert
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (99.99m, 50m, 49.995m),
        (0m, 15m, 0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountTestData))]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountTestData =>
    [
        (100m, -1m),
        (100m, 101m),
        (50m, -0.01m),
        (50m, 100.01m),
    ];

    #endregion

    #region FormatPrice - DataRow tests

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default USD")]
    [DataRow(5.5, "€", "€5.50", DisplayName = "Euro symbol")]
    [DataRow(0.0, "£", "£0.00", DisplayName = "Zero with GBP")]
    [DataRow(1234.567, "$", "$1234.57", DisplayName = "Rounds to 2 decimals")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

